const minutes = query.minutes ?? 60;
const minLevel = query.min_level ?? 3;
const rangeSeconds = minutes * 60;

const token = $env.GRAYLOG_API_TOKEN;
const streamId = $env.GRAYLOG_STREAM_ID;
const encoded = Buffer.from(`${token}:token`).toString('base64');

const response = await $http.request({
  method: 'GET',
  url: 'http://192.168.5.20:9000/api/search/universal/relative',
  headers: {
    'Authorization': `Basic ${encoded}`,
    'Accept': 'application/json',
    'X-Requested-By': 'n8n'
  },
  qs: {
    query: `streams:${streamId} AND level:<=${minLevel}`,
    range: rangeSeconds,
    limit: 50,
    fields: 'timestamp,source,message,level,facility',
    sort: 'timestamp:desc'
  }
});

const messages = response.messages || [];

if (messages.length === 0) {
  return 'No WiFi errors found in the specified time range.';
}

const levelMap = { 0:'EMERGENCY', 1:'ALERT', 2:'CRITICAL', 3:'ERROR', 4:'WARNING', 5:'NOTICE', 6:'INFO', 7:'DEBUG' };

const formatted = messages.map(m => {
  const f = m.message;
  const level = levelMap[f.level] || `LEVEL_${f.level}`;
  return `[${f.timestamp}] ${level} | ${f.source} | ${f.message}`;
}).join('\n');

return `Found ${messages.length} WiFi log entries:\n\n${formatted}`;
